", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": " ติดตั้งโดยทีมงานมืออาชีพ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "รับประกันคุณภาพวัสดุและงานติดตั้ง", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": " มีแบบหญ้าเทียมให้เลือกหลายรุ่น รองรับทั้งกิจกรรมหนักและเบา", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}], "direction": "ltr"}], "listType": "bullet", "direction": "ltr"}, {"tag": "h2", "type": "heading", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "สรุป", "type": "text", "style": "", "detail": 0, "format": 1, "version": 1}], "direction": "ltr", "textFormat": 1}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "หากคุณกำลังมองหาพื้นสนามที่ใช้งานได้หลากหลาย ทนทาน ดูแลง่าย และปลอดภัยสำหรับทุกคนในชุมชนหรือโรงเรียน", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}, {"mode": "normal", "text": " ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"mode": "normal", "text": "หญ้าเทียมสนาม MULTISPORT จาก About Grass", "type": "text", "style": "", "detail": 0, "format": 1, "version": 1}, {"mode": "normal", "text": " คือตัวเลือกที่คุ้มค่าที่สุดในระยะยาว", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "📞 02 -398 5088", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}, {"mode": "normal", "text": " ➡️ เยี่ยมชมได้ที่:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"id": "689306062eee932dcc8c4463", "type": "link", "fields": {"url": "https://www.aboutgrass.com/product/multi-sport-and-playground", "newTab": false, "linkType": "custom"}, "format": "", "indent": 0, "version": 3, "children": [{"mode": "normal", "text": " https://www.aboutgrass.com/product/multi-sport-and-playground", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}], "direction": "ltr", "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [], "direction": null, "textStyle": "", "textFormat": 0}], "direction": "ltr"}}	2025-08-06 07:59:14.741+00	2025-08-06 07:31:28.091+00	draft	2025-08-06 07:58:56.556+00	2025-08-06 07:59:14.966+00	f	t	หญ้าเทียมสนาม MULTISPORT พื้นสนามกีฬาอเนกประสงค์	573	ติดตั้งหญ้าเทียมสนาม MULTISPORT สำหรับโรงเรียน คอนโด และหมู่บ้าน รองรับกีฬาหลายประเภท พื้นนุ่ม ทนทาน พร้อมบริการครบวงจร	หญ้าเทียมสนาม MULTISPORT,โรงเรียน, คอนโด, สนามหมู่บ้าน 
